function id(a){return document.getElementById(a)}function cls(a){return document.getElementsByClassName(a)}let player=id('presentation'),slidemax=parseInt(player.getAttribute('data-slidemax')),slideaud=player.getAttribute('data-slug'),control=id('slide-control'),image=id('slide-image'),audio=id('slide-audio');function audiostart(){audio.load(),audio.play()}function resetslide(){let a=window.location.href+'slide/slide-1.jpg',b='https://archive.org/download/'+slideaud+'/slide-1.mp3';player.setAttribute("data-slide",'1'),image.src=a,audio.src=b,audio.pause(),audio.currentTime=0}function slideopen(){if(screen.width<960){player.requestFullscreen(),screen.orientation.lock("landscape-primary");let a='max-width:'+screen.height+'px; max-height:'+screen.width+'px';player.setAttribute('style',a)}player.setAttribute('data-player','play'),id('player').classList.add('flex'),audio.src=player.getAttribute('data-audio'),audiostart()}function slideclose(){screen.width<960&&(document.exitFullscreen(),image.setAttribute('style',''),screen.orientation.lock("portrait-primary")),resetslide(),player.setAttribute('data-player',''),id('player').classList.remove('flex')}function slidepause(){audio.pause(),control.setAttribute("data-icon","play")}function slideplay(){audio.play(),control.setAttribute("data-icon","pause")}function slidenext(){let a=player.getAttribute('data-slide');if(a<slidemax){let b=parseInt(a)+1;player.setAttribute("data-slide",b);let c=window.location.href+'slide/slide-'+b+'.jpg',d='https://archive.org/download/'+slideaud+'/slide-'+b+'.mp3';image.src=c,audio.src=d,audiostart()}}function slideprev(){let a=player.getAttribute('data-slide');if(a>1){let b=parseInt(a)-1,c=window.location.href+'slide/slide-'+b+'.jpg',d='https://archive.org/download/'+slideaud+'/slide-'+b+'.mp3';player.setAttribute("data-slide",b),image.src=c,audio.src=d,audiostart()}else resetslide()}audio.onended=function(){slidenext()};let slideaction=cls('action');for(var i=0;i<slideaction.length;i++)slideaction[i].onclick=function(){switch(this.getAttribute('data-action')){case"slide-prev":slideprev();break;case"slide-next":slidenext();break;case"slide-pause":slidepause();break;case"slide-play":slideplay();break;case"slide-open":slideopen();break;case"slide-exit":slideclose()}}